import { NotAuthenticatedError } from "./errors.js";
import { isValidStudioRoute } from "./studioRoutes.js";
const DEFAULT_POLL_INTERVAL_MS = 1500;
export async function createAgentSession(opts) {
    if (!opts.apiKey) {
        throw new NotAuthenticatedError();
    }
    const url = `${opts.serviceUrl}/api/studio/sessions`;
    const res = await fetch(url, {
        method: "POST",
        headers: {
            Authorization: `Bearer ${opts.apiKey}`,
            "Content-Type": "application/json",
            ...opts.extraHeaders,
        },
        body: JSON.stringify({ sessionId: opts.sessionId }),
    });
    if (!res.ok) {
        if (res.status === 401) {
            throw new NotAuthenticatedError("Session expired or invalid. Run the login command to re-authenticate.");
        }
        throw new Error(`createAgentSession failed (${res.status}): ${await res.text()}`);
    }
    return (await res.json());
}
/**
 * Push an event into a session's event stream. Use this to send commands
 * (e.g. "agent:navigate") to the browser tab paired with `sessionId`.
 * Event types and data shapes come from the typed `AgentEventDataMap`
 * union.
 */
export async function pushAgentSessionEvent(client, event) {
    const url = `${client.serviceUrl}/api/studio/events`;
    const res = await fetch(url, {
        method: "POST",
        headers: {
            Authorization: `Bearer ${client.apiKey}`,
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            session: client.sessionId,
            type: event.type,
            data: event.data,
        }),
    });
    if (!res.ok) {
        throw new Error(`pushAgentSessionEvent failed (${res.status}): ${await res.text()}`);
    }
    return (await res.json());
}
/**
 * Continuously poll a session's event stream. Each poll request is short-
 * lived (Vercel-friendly) and asks for events strictly after `since`. The
 * cursor advances after each successful poll.
 *
 * The loop runs until `abortSignal` fires. Network errors are surfaced via
 * `onError` and the loop continues; transient failures should not terminate
 * the channel.
 */
export async function pollAgentSessionEvents(opts) {
    const interval = opts.intervalMs ?? DEFAULT_POLL_INTERVAL_MS;
    const client = {
        serviceUrl: opts.serviceUrl,
        apiKey: opts.apiKey ?? "",
        sessionId: opts.sessionId,
    };
    let since = opts.startCursor ?? null;
    while (!opts.abortSignal.aborted) {
        try {
            const url = new URL(`${opts.serviceUrl}/api/studio/events`);
            url.searchParams.set("session", opts.sessionId);
            if (since) {
                url.searchParams.set("since", since);
            }
            const authHeaders = opts.apiKey
                ? { Authorization: `Bearer ${opts.apiKey}` }
                : { [STUDIO_SESSION_SCOPE_HEADER]: STUDIO_SESSION_SCOPE_VALUE };
            const res = await fetch(url.toString(), {
                headers: authHeaders,
                signal: opts.abortSignal,
            });
            if (res.ok) {
                const body = (await res.json());
                for (const event of body.events) {
                    if (event.type === "studio:ping") {
                        sendPong(client, event.data.ts).catch(() => { });
                    }
                    opts.onEvent(event);
                    since = event.id;
                }
                if (opts.onBrowserStatus &&
                    typeof body.browserConnected === "boolean") {
                    opts.onBrowserStatus(body.browserConnected);
                }
            }
            else if (opts.onError) {
                opts.onError(new Error(`agent-session poll failed (${res.status})`));
            }
        }
        catch (err) {
            if (opts.abortSignal.aborted) {
                return;
            }
            if (opts.onError) {
                opts.onError(err instanceof Error ? err : new Error(String(err)));
            }
        }
        await new Promise((resolve) => {
            const onAbort = () => {
                clearTimeout(timer);
                resolve();
            };
            const timer = setTimeout(() => {
                opts.abortSignal.removeEventListener("abort", onAbort);
                resolve();
            }, interval);
            opts.abortSignal.addEventListener("abort", onAbort, { once: true });
        });
    }
}
/**
 * Header that opts a keyless request into the anonymous, sessionId-scoped
 * tier of `/api/studio/events`. Used by `pollAgentSessionEvents` and
 * `fetchStreamTip` when no API key is available.
 */
const STUDIO_SESSION_SCOPE_HEADER = "x-bitfab-auth-scope";
const STUDIO_SESSION_SCOPE_VALUE = "session";
/**
 * Read the current tail of a session's event stream and return the latest
 * event id (the "tip"), or undefined if the stream is empty or unreachable.
 *
 * Event pollers start strictly AFTER this id so they only react to events
 * produced after they attached — never history replayed from the stream. The
 * hazard is real in both directions: a previous deliberate end's
 * `session-ended` would instantly terminate a command that just reused the
 * session (the window parked on the close page is deliberately reusable), and
 * an old `tracePlan:confirmed`-style event would double-fire into a fresh
 * command's logic.
 *
 * The GET returns events ascending from `since`, so a single unpaged read
 * yields the FIRST batch — whose last id stops being the tip once the stream
 * outgrows one page. Page until a partial batch to find the true tail. The
 * iteration cap is a safety valve well above the server's stream MAXLEN.
 */
export async function fetchStreamTip(client) {
    const PAGE_LIMIT = 500;
    const MAX_PAGES = 10;
    let tip;
    const authHeaders = client.apiKey
        ? { Authorization: `Bearer ${client.apiKey}` }
        : { [STUDIO_SESSION_SCOPE_HEADER]: STUDIO_SESSION_SCOPE_VALUE };
    try {
        for (let page = 0; page < MAX_PAGES; page++) {
            const url = new URL(`${client.serviceUrl}/api/studio/events`);
            url.searchParams.set("session", client.sessionId);
            url.searchParams.set("limit", String(PAGE_LIMIT));
            if (tip) {
                url.searchParams.set("since", tip);
            }
            const res = await fetch(url.toString(), {
                headers: authHeaders,
            });
            if (!res.ok) {
                return tip;
            }
            const body = (await res.json());
            const events = body.events ?? [];
            const last = events.at(-1)?.id;
            if (!last) {
                return tip;
            }
            tip = last;
            if (events.length < PAGE_LIMIT) {
                return tip;
            }
        }
    }
    catch {
        // Unreachable stream — callers treat undefined as "poll from the start".
    }
    return tip;
}
export async function closeStudio(client, message) {
    return pushAgentSessionEvent(client, {
        type: "agent:close-studio",
        data: message ? { message } : {},
    });
}
export async function navigateStudio(client, path) {
    if (!isValidStudioRoute(path)) {
        throw new Error(`Studio route not allowed: ${path}`);
    }
    return pushAgentSessionEvent(client, {
        type: "agent:navigate",
        data: { path },
    });
}
const STUDIO_NAVIGATE_ACK_TIMEOUT_MS = 12_000;
const PING_PONG_TIMEOUT_MS = 5_000;
function awaitNavigateAck(client, path, ackTimeoutMs, startCursor) {
    const abortController = new AbortController();
    let timer = null;
    const result = new Promise((resolve) => {
        timer = setTimeout(() => {
            resolve({ acked: false, reason: "timeout" });
            abortController.abort();
        }, ackTimeoutMs);
        const pathOnly = path.split("?")[0];
        pollAgentSessionEvents({
            serviceUrl: client.serviceUrl,
            apiKey: client.apiKey,
            sessionId: client.sessionId,
            // Only a FRESH ack counts: polling from the stream start would match a
            // historical `studio:navigated` for the same path (sessions revisit the
            // same routes constantly), false-acking a navigation a dead or
            // disconnected window never processed — masking exactly the
            // unreachable-window case that must gate.
            startCursor,
            abortSignal: abortController.signal,
            onEvent: (event) => {
                if (event.type === "studio:navigated" && event.data.path === pathOnly) {
                    if (timer) {
                        clearTimeout(timer);
                    }
                    resolve({ acked: true });
                    abortController.abort();
                    return;
                }
                if (event.type === "studio:navigation-blocked" &&
                    event.data.path === pathOnly) {
                    if (timer) {
                        clearTimeout(timer);
                    }
                    resolve({
                        acked: false,
                        reason: "blocked",
                        blockedReason: event.data.reason,
                    });
                    abortController.abort();
                    return;
                }
                // Only a real teardown means the window can't ack. `session-ended`
                // and `session-closed` are NOT terminal here: an ended session's
                // window stays alive when the browser refuses `window.close()`
                // (parked on the close page) and can still navigate and ack.
                if (event.type === "studio:window-closed") {
                    if (timer) {
                        clearTimeout(timer);
                    }
                    resolve({ acked: false, reason: "window-closed" });
                    abortController.abort();
                }
            },
            onError: () => { },
        }).catch(() => {
            if (abortController.signal.aborted) {
                return;
            }
            if (timer) {
                clearTimeout(timer);
            }
            resolve({ acked: false, reason: "timeout" });
        });
    });
    return result;
}
function awaitPong(client, pingTs) {
    return new Promise((resolve) => {
        const abortController = new AbortController();
        let received = false;
        const timer = setTimeout(() => {
            abortController.abort();
            resolve(false);
        }, PING_PONG_TIMEOUT_MS);
        pollAgentSessionEvents({
            serviceUrl: client.serviceUrl,
            apiKey: client.apiKey,
            sessionId: client.sessionId,
            abortSignal: abortController.signal,
            onEvent: (event) => {
                if (event.type === "studio:pong" &&
                    event.data.replyTo === pingTs) {
                    received = true;
                    clearTimeout(timer);
                    abortController.abort();
                    resolve(true);
                }
            },
            onError: () => { },
        }).catch(() => {
            if (!received) {
                clearTimeout(timer);
                resolve(false);
            }
        });
    });
}
export async function navigateStudioAndAwaitAck(client, path, opts = {}) {
    const ackTimeoutMs = opts.ackTimeoutMs ?? STUDIO_NAVIGATE_ACK_TIMEOUT_MS;
    if (!isValidStudioRoute(path)) {
        return { acked: false, reason: "invalid-route" };
    }
    // Capture the tip BEFORE pushing the navigate so the ack wait only sees
    // events our own push produced (see the replay note in awaitNavigateAck).
    const startCursor = await fetchStreamTip(client);
    try {
        await navigateStudio(client, path);
    }
    catch {
        return { acked: false, reason: "push-failed" };
    }
    const result = await awaitNavigateAck(client, path, ackTimeoutMs, startCursor);
    if (result.acked || result.reason !== "timeout") {
        return result;
    }
    const pingTs = Date.now();
    try {
        await pushAgentSessionEvent(client, {
            type: "agent:ping",
            data: { ts: pingTs },
        });
    }
    catch {
        return result;
    }
    const pongReceived = await awaitPong(client, pingTs);
    if (pongReceived) {
        return { acked: true };
    }
    return result;
}
export async function sendPing(client) {
    return pushAgentSessionEvent(client, {
        type: "agent:ping",
        data: { ts: Date.now() },
    });
}
export async function sendPong(client, replyTo) {
    return pushAgentSessionEvent(client, {
        type: "agent:pong",
        data: { ts: Date.now(), replyTo },
    });
}
export async function isStudioBrowserConnected(client, opts = {}) {
    const timeoutMs = opts.timeoutMs ?? 2_000;
    try {
        const url = new URL(`${client.serviceUrl}/api/studio/events`);
        url.searchParams.set("session", client.sessionId);
        url.searchParams.set("limit", "1");
        const res = await fetch(url.toString(), {
            headers: { Authorization: `Bearer ${client.apiKey}` },
            signal: AbortSignal.timeout(timeoutMs),
        });
        if (!res.ok) {
            return false;
        }
        const body = (await res.json());
        return body.browserConnected === true;
    }
    catch {
        return false;
    }
}
export async function getStudioState(client) {
    const url = new URL(`${client.serviceUrl}/api/studio/state`);
    url.searchParams.set("session", client.sessionId);
    const res = await fetch(url.toString(), {
        headers: { Authorization: `Bearer ${client.apiKey}` },
    });
    if (!res.ok) {
        throw new Error(`getStudioState failed (${res.status}): ${await res.text()}`);
    }
    return (await res.json());
}
